import hashlib
import secrets

def file_hash(file_path):
    hasher = hashlib.sha256()
    with open(file_path, 'rb') as f:
        while chunk := f.read(8192):
            hasher.update(chunk)
    return hasher.hexdigest()

# Example usage
file_path = 'example.txt'
hash_value = file_hash(file_path)
